## CODE STRUCTURE ISSUES

### 10. **Multiple Object.assign in Reduce Functions**
**Files:** 
- `/Users/anotonio.silva/antonio/belt/packages/tools/src/helpers/list.ts` (Line 9)
- `/Users/anotonio.silva/antonio/belt/packages/tools/src/helpers/object-utils.ts` (Line 254)

**Lines:** 
```typescript
// list.ts
export function reduce<Result extends object, const Item>(
  items: ReadonlyArray<Item>,
  reducer: (next: Item) => Partial<Result> | undefined,
): Result {
  const result = {} as Result;
  for (const item of items) {
    const next = reducer(item);
    if (next !== undefined) {
      Object.assign(result, next);  // ← Per item
    }
  }
  return result;
}

// object-utils.ts
export function reduceObject<Result extends object, O extends object>(
  items: O,
  reducer: (pair: ObjectEntries<O>[number]) => Partial<Result>,
): Result {
  const result = {} as Result;
  for (const entry of objectEntries(items)) {
    Object.assign(result, reducer(entry));  // ← Per entry
  }
  return result;
}
```

**Problem:** Object.assign called in loop for each item. With 100 items, 100 property copies. Should accumulate object and merge once, or use direct assignment.

**Impact:** Medium - Used in hot paths like `maskData()` and `flatRecordRecords()`.

**Recommendation:** 
```typescript
// Better: accumulate properties
const accumulated: any = {};
for (const item of items) {
  const next = reducer(item);
  if (next) Object.assign(accumulated, next);  // Single merge per reducer
}
```

Or use destructuring for better performance on modern engines.

