**Issue:** Regex pattern created during module initialization but uses string concatenation.

```typescript
export const MSUnits = Object.keys(MSUnitMapper) as (keyof typeof MSUnitMapper)[];

export const MS_REGEX = new RegExp(`^(\\d+)(${MSUnits.join('|')})$`);  // ← Dynamic regex

